#floating-toc-btn{position:fixed;bottom:24px;right:24px;z-index:998;background:var(--pp-red);color:#fff;border:2px solid var(--pp-cheese);width:56px;height:56px;border-radius:50%;cursor:pointer;box-shadow:0 6px 20px rgba(215,40,47,.4);display:flex;align-items:center;justify-content:center;transition:all .2s}
