#toc-drawer{position:fixed;top:0;right:0;bottom:0;width:min(400px,92vw);background:var(--pp-cream);z-index:1501;padding:0;overflow-y:auto;transform:translateX(100%);transition:transform .3s cubic-bezier(.4,0,.2,1);box-shadow:-8px 0 30px rgba(0,0,0,.35);display:flex;flex-direction:column}
