.toc-drawer-header{display:flex;justify-content:space-between;align-items:center;padding:16px 20px;background:var(--pp-charcoal);color:#fff;border-bottom:3px solid var(--pp-cheese);position:sticky;top:0;z-index:2}
.toc-drawer-title{font-family:'Bebas Neue',sans-serif;color:var(--pp-cheese);font-size:1.4rem;letter-spacing:.06em}
