#toc-drawer-nav a:hover{background:var(--pp-red);color:#fff;border-color:var(--pp-red);border-left-color:var(--pp-cheese);transform:translateX(3px);opacity:1;box-shadow:0 2px 8px rgba(215,40,47,.3)}
