/* COLLAPSIBLE SECTIONS */
.card.collapsible{padding:0;overflow:hidden;transition:all .3s ease}
.section-header-bar{display:flex;align-items:center;justify-content:space-between;padding:22px 30px;cursor:pointer;user-select:none;background:linear-gradient(135deg,var(--pp-white) 0%,rgba(244,200,66,.08) 100%);transition:background .2s;border-bottom:1px solid transparent}
