a:hover{opacity:.75}
.eyebrow{font-family:'DM Mono',monospace;font-size:11px;letter-spacing:.2em;text-transform:uppercase;color:var(--pp-red);margin-bottom:8px;display:block;font-weight:600}
.card{background:var(--pp-white);border-radius:16px;padding:36px;margin-bottom:20px;box-shadow:0 2px 20px rgba(31,26,23,.07);border:1px solid rgba(215,40,47,.12)}

/* HERO */
#hero{max-width:100%;padding:0;margin:0;background:linear-gradient(135deg,var(--pp-charcoal) 0%,var(--pp-red-deep) 50%,var(--pp-red) 100%);position:relative;overflow:hidden}
