.hero-stats{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:14px;margin:28px 0}
.hero-stat{background:rgba(255,255,255,.08);border:1px solid rgba(244,200,66,.3);border-radius:12px;padding:18px;backdrop-filter:blur(4px)}
.hero-stat-num{font-family:'Bebas Neue',sans-serif;font-size:2.1rem;color:var(--pp-cheese);line-height:1;margin-bottom:6px;letter-spacing:.02em}
