.product-img-wrap{position:relative;aspect-ratio:1/1;background:linear-gradient(135deg,var(--pp-cream) 0%,var(--pp-cream-deep) 100%);display:flex;align-items:center;justify-content:center;overflow:hidden;max-width:200px;margin:0 auto;width:100%}
.product-img-wrap img{width:100%;height:100%;object-fit:contain;display:block;padding:8px}
.product-card.bundle .product-img-wrap{max-width:150px}
