.product-img-wrap .product-color-fallback{display:none;flex-direction:column;align-items:center;justify-content:center;width:100%;height:100%;font-family:'Bebas Neue',sans-serif;font-size:1.1rem;letter-spacing:.08em;color:#fff;text-shadow:0 2px 4px rgba(0,0,0,.25);padding:14px;text-align:center}
.product-img-wrap img[data-failed="1"]{display:none}
