.product-color-swatch{width:64px;height:64px;border-radius:50%;background:#fff;margin-bottom:10px;border:3px solid rgba(255,255,255,.45);box-shadow:0 4px 12px rgba(0,0,0,.18)}
.product-badge-corner{position:absolute;top:10px;left:10px;background:var(--pp-cheese);color:var(--pp-charcoal);font-family:'DM Mono',monospace;font-size:10px;font-weight:700;letter-spacing:.06em;padding:4px 10px;border-radius:14px;text-transform:uppercase;box-shadow:0 2px 6px rgba(0,0,0,.15)}
.product-badge-corner.shark{background:var(--pp-red);color:#fff}
.product-card-body{padding:16px 18px 18px;display:flex;flex-direction:column;gap:8px;flex:1}
.product-name{font-family:'Fraunces',serif;font-size:1.05rem;font-weight:800;color:var(--pp-charcoal);line-height:1.25}
.product-meta{font-family:'DM Mono',monospace;font-size:10.5px;letter-spacing:.08em;text-transform:uppercase;color:var(--pp-red);font-weight:700}
.product-spec{font-size:13px;color:var(--pp-text);line-height:1.55}
.product-spec strong{color:var(--pp-charcoal)}
.product-spec-list{list-style:none;padding:0;margin:4px 0;font-size:12.5px;color:var(--pp-text);line-height:1.5}
.product-spec-list li{padding:3px 0 3px 16px;position:relative}
.product-spec-list li::before{content:"🍕";position:absolute;left:0;top:3px;font-size:9px}
.product-link{margin-top:auto;display:inline-flex;align-items:center;gap:6px;background:var(--pp-red);color:#fff!important;font-family:'Inter',sans-serif;font-size:12.5px;font-weight:700;text-decoration:none!important;padding:9px 14px;border-radius:8px;align-self:flex-start;transition:background .15s,transform .15s}
.product-link:hover{background:var(--pp-red-deep);transform:translateY(-1px);opacity:1}
.product-tags{display:flex;flex-wrap:wrap;gap:5px;margin-top:4px}
.product-tag{background:rgba(244,200,66,.28);color:var(--pp-charcoal);font-size:10.5px;padding:2px 7px;border-radius:10px;font-weight:600;font-family:'DM Mono',monospace;letter-spacing:.03em}
.product-color-row{display:flex;flex-wrap:wrap;gap:6px;margin-top:4px;align-items:center}
.color-dot{width:18px;height:18px;border-radius:50%;border:2px solid #fff;box-shadow:0 1px 3px rgba(0,0,0,.25)}

/* SPEC TABLE for primary product */
.spec-table{background:#fff;border:1px solid rgba(215,40,47,.18);border-radius:10px;padding:18px 22px;margin:14px 0;font-size:13.5px;line-height:1.6}
.spec-table dl{display:grid;grid-template-columns:max-content 1fr;gap:8px 18px}
.spec-table dt{font-family:'DM Mono',monospace;font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:var(--pp-red);font-weight:700;padding-top:2px}
.spec-table dd{color:var(--pp-text);margin:0}
.spec-table dd strong{color:var(--pp-charcoal)}
