.feature-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin:14px 0 8px}
.feature-tile{background:linear-gradient(135deg,#fff 0%,var(--pp-cream) 100%);border:1px solid rgba(215,40,47,.18);border-left:4px solid var(--pp-cheese);border-radius:10px;padding:14px 16px}
.feature-tile-icon{font-size:1.4rem;margin-bottom:6px;display:block;line-height:1}
.feature-tile h4{margin-bottom:4px;font-size:13.5px;color:var(--pp-charcoal)}
.feature-tile p{margin:0;font-size:12.5px;color:var(--pp-text-muted);line-height:1.5}

/* PILLARS */
.pillars{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:14px;margin-top:20px}
.pillar{background:linear-gradient(135deg,var(--pp-white) 0%,rgba(244,200,66,.18) 100%);padding:22px;border-radius:12px;border-left:4px solid var(--pp-red);transition:transform .2s}
.pillar:hover{transform:translateY(-3px)}
.pillar-icon{font-size:1.8rem;margin-bottom:10px;display:block}
.pillar h4{color:var(--pp-charcoal);margin-bottom:6px;font-size:1rem}
.pillar p{font-size:13px;color:var(--pp-text-muted);margin-bottom:0;line-height:1.5}

/* TONE */
.tone-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:14px;margin-top:20px}
.tone{background:var(--pp-cream);padding:20px;border-radius:10px;border-top:4px solid var(--pp-red)}
.tone-label{font-weight:700;color:var(--pp-charcoal);font-size:14px;margin-bottom:6px}
.tone-desc{font-size:13px;color:var(--pp-text-muted);margin-bottom:10px}
.tone-ex{font-family:'Fraunces',serif;font-style:italic;color:var(--pp-red);font-size:14px;border-left:3px solid var(--pp-cheese);padding-left:10px;line-height:1.5}

/* DO/DONT */
.do-dont{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:16px}
.do-dont > div{padding:20px;border-radius:10px}
.do{background:rgba(46,125,50,.08);border:1px solid var(--pp-basil)}
.dont{background:rgba(184,57,31,.08);border:1px solid var(--pp-danger)}
.do h4{color:var(--pp-basil)}
.dont h4{color:var(--pp-danger)}
.do ul,.dont ul{padding-left:18px;margin-top:8px}
.do li,.dont li{margin-bottom:6px;font-size:13px}
@media (max-width:640px){.do-dont{grid-template-columns:1fr}}

/* ADJ */
.adj-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-top:18px}
.adj{background:#fff;padding:16px;border-radius:10px;border:1px solid rgba(215,40,47,.2)}
.adj-title{font-weight:700;color:var(--pp-red);font-size:14px;margin-bottom:5px;font-family:'DM Mono',monospace;text-transform:uppercase;letter-spacing:.05em}
.adj-desc{font-size:13px;color:var(--pp-text-muted);line-height:1.5}

/* COLOR PALETTE */
.palette{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-top:16px}
.swatch{border-radius:10px;overflow:hidden;border:1px solid rgba(31,26,23,.12)}
