.type-spec{background:#fff;padding:18px;border-radius:10px;border:1px solid rgba(215,40,47,.2);margin-bottom:10px}
.type-spec-name{font-size:12px;font-family:'DM Mono',monospace;color:var(--pp-red);text-transform:uppercase;letter-spacing:.1em;margin-bottom:6px;font-weight:700}
.type-spec-use{font-size:12px;color:var(--pp-text-muted);margin-bottom:10px}

/* PERSONAS */
.personas{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:14px;margin-top:18px}
.persona{background:linear-gradient(135deg,var(--pp-white) 0%,var(--pp-cream) 100%);padding:22px;border-radius:12px;border:1px solid rgba(215,40,47,.18)}
.persona-name{font-family:'Fraunces',serif;font-size:1.3rem;font-weight:800;color:var(--pp-charcoal);margin-bottom:4px}
.persona-type{font-family:'DM Mono',monospace;font-size:11px;color:var(--pp-red);text-transform:uppercase;letter-spacing:.1em;margin-bottom:10px;font-weight:700}
.persona-desc{font-size:13px;color:var(--pp-text-muted);margin-bottom:10px;line-height:1.55}
.persona-focus{font-size:12px;color:var(--pp-charcoal)}
.persona-focus strong{color:var(--pp-red)}

/* OBJECTIONS */
.objection{background:#fff;border-radius:10px;padding:20px;margin-bottom:12px;border-left:4px solid var(--pp-cheese)}
.objection-q{font-weight:700;color:var(--pp-danger);margin-bottom:8px;font-size:14px}
.objection-a{color:var(--pp-text);font-size:14px;line-height:1.6}
.objection-q::before{content:"💬 Objection: ";font-weight:800;color:var(--pp-red)}
