.journey{overflow-x:auto}

/* STATS */
.stat-boxes{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:14px;margin-top:18px}
.stat-box{background:linear-gradient(135deg,var(--pp-red) 0%,var(--pp-red-deep) 100%);color:#fff;padding:22px;border-radius:12px;text-align:center}
.stat-big{font-family:'Bebas Neue',sans-serif;font-size:2.6rem;line-height:1;margin-bottom:6px;color:var(--pp-cheese);letter-spacing:.02em}
.stat-lbl{font-size:12px;line-height:1.4;opacity:.95}

/* MARKETING ANGLES */
.angles{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:14px;margin-top:16px}
.angle{background:#fff;padding:20px;border-radius:10px;border-top:4px solid var(--pp-cheese)}
.angle h4{color:var(--pp-charcoal);margin-bottom:8px}
.angle-row{font-size:13px;margin-bottom:5px}
.angle-row strong{color:var(--pp-red);font-family:'DM Mono',monospace;text-transform:uppercase;font-size:11px;letter-spacing:.08em}

/* HOOKS */
.hooks{counter-reset:hook;list-style:none;padding:0;margin-top:14px}
.hooks li{counter-increment:hook;padding:12px 14px 12px 48px;margin-bottom:8px;background:#fff;border-radius:8px;position:relative;font-size:14px;border:1px solid rgba(215,40,47,.18)}
.hooks li::before{content:counter(hook,decimal-leading-zero);position:absolute;left:14px;top:50%;transform:translateY(-50%);font-family:'DM Mono',monospace;color:var(--pp-red);font-weight:700;font-size:13px}

/* FAQ */
.faq-item{background:#fff;border-radius:10px;padding:20px;margin-bottom:10px;border:1px solid rgba(215,40,47,.18)}
.faq-q{font-weight:700;color:var(--pp-charcoal);margin-bottom:10px;padding-left:30px;position:relative;font-size:14px}
.faq-q::before{content:"Q";position:absolute;left:0;top:-2px;width:22px;height:22px;background:var(--pp-red);color:#fff;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;font-family:'DM Mono',monospace}
.faq-a{color:var(--pp-text-muted);padding-left:30px;font-size:14px;line-height:1.6}

/* GLOSSARY */
.glossary{background:#fff;padding:24px;border-radius:10px;border:1px solid rgba(215,40,47,.15)}
.glossary dt{font-weight:700;color:var(--pp-red);font-family:'DM Mono',monospace;font-size:13px;text-transform:uppercase;letter-spacing:.05em;margin-top:14px}
.glossary dt:first-child{margin-top:0}
.glossary dd{margin-left:0;margin-top:4px;font-size:14px;color:var(--pp-text);line-height:1.55}

/* RETURN POLICY */
.policy-card{background:linear-gradient(135deg,var(--pp-cream) 0%,var(--pp-cream-deep) 100%);border:2px solid var(--pp-red);border-radius:14px;padding:30px;margin-top:10px}
.policy-card h3{color:var(--pp-charcoal);font-size:1.4rem;margin-bottom:14px;font-family:'Fraunces',serif}
.policy-card p{font-size:14px;margin-bottom:12px;color:var(--pp-text)}
.policy-contact{background:#fff;padding:14px 18px;border-radius:8px;margin-top:10px;font-size:14px;border-left:4px solid var(--pp-red)}

/* QUIZ */
#quiz-section{background:linear-gradient(135deg,var(--pp-charcoal) 0%,var(--pp-red-deep) 100%);color:#fff;border-radius:20px;padding:0;margin-top:40px;overflow:hidden}
#quiz-section h2{color:#fff;border-bottom-color:var(--pp-cheese);margin:0;padding:0;border:none}
#quiz-section .section-header-bar{background:transparent;padding:32px 30px 20px;border-bottom:1px solid rgba(244,200,66,.18)}
#quiz-section .section-header-bar:hover{background:rgba(255,255,255,.04)}
#quiz-section .section-toggle{border-color:var(--pp-cheese);color:var(--pp-cheese)}
#quiz-section .section-toggle:hover{background:var(--pp-cheese);color:var(--pp-charcoal)}
#quiz-section .section-body{padding:20px 30px 40px}
#quiz-section.collapsed .section-header-bar{border-bottom:none;border-color:transparent}
.quiz-container{background:rgba(255,255,255,.07);border-radius:14px;padding:28px;margin-top:20px;border:1px solid rgba(244,200,66,.3)}
.quiz-progress{font-family:'DM Mono',monospace;font-size:12px;color:var(--pp-cheese);letter-spacing:.1em;margin-bottom:16px;text-transform:uppercase}
.quiz-progress-bar{height:6px;background:rgba(255,255,255,.12);border-radius:3px;overflow:hidden;margin-bottom:22px}
.quiz-progress-fill{height:100%;background:var(--pp-cheese);transition:width .4s cubic-bezier(.4,0,.2,1);border-radius:3px}
.quiz-question{font-family:'Fraunces',serif;font-size:1.3rem;font-weight:700;margin-bottom:22px;line-height:1.35;color:#fff}
.quiz-options{display:flex;flex-direction:column;gap:10px}
.quiz-option{background:rgba(255,255,255,.06);border:2px solid rgba(244,200,66,.3);color:#fff;padding:14px 18px;border-radius:10px;text-align:left;font-size:14px;cursor:pointer;transition:all .2s;font-family:inherit;display:flex;align-items:center;gap:12px}
.quiz-option:hover{background:rgba(244,200,66,.18);border-color:var(--pp-cheese);transform:translateX(4px)}
.quiz-option.correct{background:#FEF9E7;border-color:#F4C842;color:var(--pp-charcoal);font-weight:700;box-shadow:0 0 0 3px rgba(244,200,66,.4);position:relative}
.quiz-option.correct::after{content:"✓ CORRECT";position:absolute;right:14px;top:50%;transform:translateY(-50%);background:var(--pp-basil);color:#fff;font-family:'DM Mono',monospace;font-size:10px;font-weight:700;letter-spacing:.1em;padding:4px 10px;border-radius:20px}
.quiz-option.incorrect{background:rgba(184,57,31,.85);border-color:#fff;color:#fff;font-weight:700;position:relative}
.quiz-option.incorrect::after{content:"✗ YOUR PICK";position:absolute;right:14px;top:50%;transform:translateY(-50%);background:#fff;color:var(--pp-danger);font-family:'DM Mono',monospace;font-size:10px;font-weight:700;letter-spacing:.1em;padding:4px 10px;border-radius:20px}
.quiz-option.show-correct{background:#FEF9E7;border-color:#F4C842;color:var(--pp-charcoal);font-weight:700;box-shadow:0 0 0 3px rgba(244,200,66,.4);position:relative}
.quiz-option.show-correct::after{content:"✓ CORRECT ANSWER";position:absolute;right:14px;top:50%;transform:translateY(-50%);background:var(--pp-basil);color:#fff;font-family:'DM Mono',monospace;font-size:10px;font-weight:700;letter-spacing:.1em;padding:4px 10px;border-radius:20px}
.quiz-option.correct .quiz-option-letter,.quiz-option.show-correct .quiz-option-letter{color:var(--pp-charcoal)}
.quiz-option:disabled{cursor:default;transform:none;opacity:1}
.quiz-option:disabled:hover{transform:none}
.quiz-option:disabled:not(.correct):not(.show-correct):not(.incorrect){opacity:.35}
.quiz-feedback{margin-top:16px;padding:14px 18px;border-radius:10px;font-size:14px;font-weight:600;animation:fadeIn .3s ease}
.quiz-feedback.right{background:#FEF9E7;border-left:4px solid #F4C842;color:var(--pp-charcoal)}
.quiz-feedback.wrong{background:#fff;border-left:4px solid var(--pp-danger);color:var(--pp-danger)}
.quiz-explain{margin-top:10px;padding:12px 14px;background:rgba(0,0,0,.03);border-radius:8px;font-size:13.5px;font-weight:400;line-height:1.6;color:var(--pp-charcoal)}
.quiz-explain strong{font-weight:700}
.quiz-explain ul{margin:8px 0 0 0;padding-left:18px}
.quiz-explain li{margin-bottom:6px}
@keyframes fadeIn{from{opacity:0;transform:translateY(-4px)}to{opacity:1;transform:translateY(0)}}
.quiz-next-btn{background:var(--pp-cheese);color:var(--pp-charcoal);border:none;padding:12px 24px;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;margin-top:14px;transition:transform .15s}
.quiz-next-btn:hover{transform:translateY(-2px)}
.quiz-option-letter{font-family:'DM Mono',monospace;font-weight:700;color:var(--pp-cheese);min-width:22px}
.quiz-start-btn,.quiz-submit-btn,.quiz-retry-btn{background:var(--pp-cheese);color:var(--pp-charcoal);border:none;padding:14px 28px;border-radius:10px;font-size:15px;font-weight:700;cursor:pointer;font-family:inherit;margin-top:18px;transition:transform .15s,box-shadow .15s}
.quiz-start-btn:hover,.quiz-submit-btn:hover,.quiz-retry-btn:hover{transform:translateY(-2px);box-shadow:0 6px 20px rgba(244,200,66,.45)}

/* COMPLETION */
.completion-wrap{padding:0}
.completion-header{background:linear-gradient(135deg,var(--pp-cheese) 0%,#FFE699 50%,var(--pp-cream) 100%);color:var(--pp-charcoal);padding:28px 24px;border-radius:14px 14px 0 0;text-align:center}
.completion-header .completion-emoji{font-size:3rem;line-height:1;margin-bottom:8px;display:block}
.completion-header h3{font-family:'Fraunces',serif;font-size:1.8rem;font-weight:800;color:var(--pp-charcoal);margin:0}
.completion-header .completion-sub{font-family:'DM Mono',monospace;font-size:11px;letter-spacing:.15em;text-transform:uppercase;color:var(--pp-red);margin-top:6px;font-weight:700}
.completion-card{background:#fff;color:var(--pp-text);border-radius:0 0 14px 14px;padding:32px 28px;box-shadow:0 4px 20px rgba(0,0,0,.08);border:1px solid rgba(215,40,47,.2);border-top:none}
.completion-brand{display:flex;align-items:center;justify-content:center;gap:14px;padding-bottom:20px;border-bottom:2px solid var(--pp-cheese);margin-bottom:22px;flex-wrap:wrap}
.completion-brand img.logo-sm{height:42px;width:auto;object-fit:contain}
.completion-brand .completion-brand-text{font-family:'Fraunces',serif;font-size:1.05rem;font-weight:700;color:var(--pp-charcoal);text-align:center;line-height:1.35}
.completion-brand .completion-brand-text small{display:block;font-family:'DM Mono',monospace;font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--pp-red);font-weight:700;margin-top:2px}
.completion-nameblock{margin-bottom:22px}
.completion-nameblock label{display:block;font-family:'DM Mono',monospace;font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--pp-red);font-weight:700;margin-bottom:8px}
.completion-nameblock input{width:100%;padding:12px 14px;border:2px solid var(--pp-cheese);border-radius:8px;font-family:'Inter',sans-serif;font-size:16px;color:var(--pp-charcoal);background:var(--pp-cream);transition:border-color .15s}
.completion-nameblock input:focus{outline:none;border-color:var(--pp-red);background:#fff}
.completion-nameblock .name-printed{display:none;font-family:'Fraunces',serif;font-size:1.5rem;font-weight:800;color:var(--pp-charcoal);padding:8px 0;border-bottom:2px solid var(--pp-charcoal)}
.completion-stats{display:grid;grid-template-columns:repeat(2,1fr);gap:14px;margin-bottom:22px}
.completion-stat{background:var(--pp-cream);border:1px solid rgba(244,200,66,.45);border-radius:10px;padding:14px 16px;text-align:center}
.completion-stat-label{display:block;font-family:'DM Mono',monospace;font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--pp-red);font-weight:700;margin-bottom:4px}
.completion-stat-value{font-family:'Fraunces',serif;font-size:1.5rem;font-weight:800;color:var(--pp-charcoal);line-height:1.1}
.completion-badge{display:inline-flex;align-items:center;gap:8px;background:var(--pp-basil);color:#fff;padding:10px 22px;border-radius:30px;font-family:'DM Mono',monospace;font-size:13px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;margin:0 auto 18px;box-shadow:0 4px 12px rgba(46,125,50,.3)}
.completion-track{text-align:center;font-family:'DM Mono',monospace;font-size:12px;letter-spacing:.1em;text-transform:uppercase;color:var(--pp-text-muted);padding-top:18px;border-top:1px dashed var(--pp-cheese)}
.completion-track strong{display:block;font-family:'Fraunces',serif;font-size:1.1rem;font-weight:700;color:var(--pp-charcoal);text-transform:none;letter-spacing:0;margin-top:4px}
.completion-actions{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin-top:24px}
.completion-actions button{background:var(--pp-cheese);color:var(--pp-charcoal);border:none;padding:12px 22px;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:transform .15s,box-shadow .15s;display:inline-flex;align-items:center;gap:8px}
.completion-actions button:hover{transform:translateY(-2px);box-shadow:0 6px 16px rgba(244,200,66,.5)}
.completion-actions button.btn-print{background:var(--pp-red);color:#fff}
.completion-actions button.btn-print:hover{box-shadow:0 6px 16px rgba(215,40,47,.4)}
.completion-center-wrap{display:flex;flex-direction:column;align-items:center}
.fail-header{background:linear-gradient(135deg,rgba(184,57,31,.18) 0%,rgba(255,180,162,.22) 100%);padding:28px 24px;border-radius:14px;text-align:center;border:1px solid rgba(184,57,31,.25)}
.fail-header .fail-emoji{font-size:3rem;line-height:1;margin-bottom:8px;display:block}
.fail-header h3{font-family:'Fraunces',serif;font-size:1.7rem;font-weight:800;color:#FFB4A2;margin:0 0 10px}
.fail-score{font-family:'DM Mono',monospace;font-size:1.8rem;font-weight:700;color:#FFB4A2;margin:8px 0 12px}
.fail-msg{color:#fff;font-size:14px;line-height:1.6;max-width:480px;margin:0 auto 18px}

/* PRINT / CERTIFICATE */
body.printing #top-nav,body.printing #floating-toc-btn,body.printing #toc-drawer,body.printing #toc-drawer-overlay,body.printing footer,body.printing section:not(#quiz-section),body.printing #quiz-section .section-header-bar,body.printing #quiz-section > .section-body > p:first-of-type,body.printing #quiz-section #quiz-start,body.printing #quiz-section #quiz-active,body.printing #quiz-section #quiz-results > p,body.printing .completion-actions{display:none !important}
body.printing{background:#fff !important}
body.printing #quiz-section{background:#fff !important;box-shadow:none !important;border-radius:0 !important;margin:0 !important;padding:0 !important}
body.printing #quiz-section .section-body{padding:0 !important;background:#fff !important}
body.printing .quiz-container{background:#fff !important;border:none !important;padding:0 !important;margin:0 !important}
body.printing #quiz-results{display:block !important}
body.printing .completion-wrap{max-width:720px;margin:0 auto}
body.printing .completion-nameblock input{display:none !important}
body.printing .completion-nameblock .name-printed{display:block !important}
@media print{
  @page{margin:0.4in}
  html,body{background:#fff !important}
  *{-webkit-print-color-adjust:exact !important;print-color-adjust:exact !important;color-adjust:exact !important}
  #top-nav,#floating-toc-btn,#toc-drawer,#toc-drawer-overlay,footer,section:not(#quiz-section),#quiz-section .section-header-bar,#quiz-section #quiz-start,#quiz-section #quiz-active,#quiz-section #quiz-results > p,.completion-actions{display:none !important}
  #quiz-section{background:#fff !important;box-shadow:none !important;border-radius:0 !important;color:#1F1A17 !important}
  #quiz-section .section-body{padding:10px 0 !important;background:#fff !important}
  .quiz-container{background:#fff !important;border:none !important;padding:0 !important}
  .completion-nameblock input{display:none !important}
  .completion-nameblock .name-printed{display:block !important}
  .completion-header{background:linear-gradient(135deg,#F4C842 0%,#FFE699 50%,#FFF5E1 100%) !important;color:#1F1A17 !important}
  .completion-header h3,.completion-header .completion-sub{color:#1F1A17 !important}
  .completion-stat{background:#FFF5E1 !important;border:1px solid #F4C842 !important}
  .completion-badge{background:#2E7D32 !important;color:#fff !important}
}

/* CREATIVES */
.creative-intro{background:linear-gradient(135deg,var(--pp-cream) 0%,#fff 100%);border:1px solid rgba(215,40,47,.25);border-left:4px solid var(--pp-red);border-radius:12px;padding:22px 24px;margin:14px 0 22px;font-size:14.5px;line-height:1.65;color:var(--pp-text)}
.creative-intro strong{color:var(--pp-charcoal)}
.pattern-list{counter-reset:pat;list-style:none;padding:0;margin:18px 0 6px;display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px}
.pattern-list li{counter-increment:pat;background:#fff;border-radius:10px;padding:16px 18px 16px 56px;position:relative;border-top:4px solid var(--pp-red);font-size:13.5px;line-height:1.55;color:var(--pp-text)}
.pattern-list li::before{content:counter(pat);position:absolute;left:14px;top:14px;width:30px;height:30px;display:flex;align-items:center;justify-content:center;background:var(--pp-red);color:#fff;border-radius:50%;font-family:'DM Mono',monospace;font-size:13px;font-weight:700}
.pattern-list .pat-title{display:block;font-family:'Fraunces',serif;font-weight:800;color:var(--pp-charcoal);font-size:15px;margin-bottom:4px}
.through-line{margin-top:18px;background:var(--pp-charcoal);color:#fff;border-radius:12px;padding:20px 24px;font-size:14.5px;line-height:1.6;border-left:5px solid var(--pp-cheese)}
.through-line strong{color:var(--pp-cheese);font-weight:800;letter-spacing:.02em}
.creative-gallery{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:18px;margin-top:22px}
.creative-card{background:#fff;border:1px solid rgba(215,40,47,.2);border-radius:12px;padding:14px;display:flex;flex-direction:column;gap:10px;transition:transform .15s,box-shadow .15s}
.creative-card:hover{transform:translateY(-2px);box-shadow:0 6px 18px rgba(31,26,23,.12)}
.creative-img{width:100%;height:auto;border-radius:8px;background:var(--pp-cream);display:block;aspect-ratio:1/1;object-fit:cover}
.creative-meta{font-family:'DM Mono',monospace;font-size:10.5px;letter-spacing:.1em;text-transform:uppercase;color:var(--pp-red);font-weight:700}
.creative-caption{font-size:13px;line-height:1.55;color:var(--pp-text)}
.creative-caption strong{color:var(--pp-charcoal);display:block;font-family:'Fraunces',serif;font-size:14.5px;margin-bottom:4px}
.creative-tags{display:flex;flex-wrap:wrap;gap:6px;margin-top:4px}
.creative-tag{background:rgba(244,200,66,.28);color:var(--pp-charcoal);font-size:11px;padding:3px 8px;border-radius:12px;font-weight:600}
.creative-img-placeholder{width:100%;aspect-ratio:1/1;border-radius:8px;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:18px;background:linear-gradient(135deg,var(--pp-charcoal) 0%,var(--pp-red-deep) 100%);color:var(--pp-cheese);font-family:'DM Mono',monospace;font-size:11px;letter-spacing:.1em;text-transform:uppercase;line-height:1.5;border:1px dashed var(--pp-cheese)}
.creative-img-placeholder .ph-emoji{font-size:2.4rem;margin-bottom:8px}
.creative-img-placeholder .ph-headline{font-family:'Fraunces',serif;text-transform:none;font-size:14px;color:#fff;font-weight:800;letter-spacing:0;margin-bottom:6px}

/* ADDRESS */
.address-block{background:#fff;border:1px solid rgba(215,40,47,.25);border-left:4px solid var(--pp-red);border-radius:10px;padding:18px 22px;font-family:'DM Mono',monospace;font-size:14px;line-height:1.55;color:var(--pp-charcoal);margin:12px 0}
.address-block .addr-label{display:block;font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--pp-red);margin-bottom:6px;font-weight:700}
.address-block strong{font-family:'Inter',sans-serif;font-size:15px;color:var(--pp-charcoal);font-weight:700}

/* ALERT */
.alert-callout{background:rgba(244,200,66,.12);border:1px solid var(--pp-cheese);border-left:5px solid var(--pp-cheese);border-radius:10px;padding:18px 22px;margin:14px 0;font-size:14px;line-height:1.6;color:var(--pp-text)}
.alert-callout.critical{background:linear-gradient(135deg,#B8391F 0%,#8B2815 100%);border:3px solid #F4C842;border-radius:12px;padding:34px 26px 24px;margin:18px 0 22px;color:#fff;box-shadow:0 6px 24px rgba(184,57,31,.4);position:relative;overflow:hidden}
.alert-callout.critical::before{content:"";position:absolute;top:0;left:0;right:0;height:6px;background:repeating-linear-gradient(45deg,#F4C842 0 12px,#1F1A17 12px 24px)}
.alert-callout strong{color:var(--pp-charcoal)}
.alert-callout.critical strong{color:#F4C842;font-weight:800}
.alert-callout-title{display:block;font-family:'DM Mono',monospace;font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--pp-red);font-weight:700;margin-bottom:6px}
.alert-callout.critical .alert-callout-title{color:#F4C842;font-size:15px;letter-spacing:.15em;font-weight:800;margin-bottom:12px;padding-bottom:10px;border-bottom:2px solid rgba(244,200,66,.4)}

/* TEAM CALLOUTS */
.team-callout{border-radius:10px;padding:16px 20px 16px 56px;margin:14px 0;font-size:13px;line-height:1.6;position:relative;background:#fff;border:1px solid rgba(215,40,47,.2);border-left:5px solid var(--pp-red)}
.team-callout::before{content:"";position:absolute;left:16px;top:18px;width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700}
.team-callout .team-tag{display:inline-block;font-family:'DM Mono',monospace;font-size:10px;letter-spacing:.12em;text-transform:uppercase;font-weight:700;padding:3px 9px;border-radius:12px;margin-bottom:6px}
.team-callout.cx{border-left-color:var(--pp-basil)}
.team-callout.cx::before{content:"📞";background:rgba(46,125,50,.18)}
.team-callout.cx .team-tag{background:var(--pp-basil);color:#fff}
.team-callout.creative{border-left-color:var(--pp-crust);background:#FFF8F0}
.team-callout.creative::before{content:"🎨";background:#FFE4C4}
.team-callout.creative .team-tag{background:var(--pp-crust);color:#fff}
.team-callout.marketing{border-left-color:#8B4789;background:#FBF5FB}
.team-callout.marketing::before{content:"📢";background:#E9D8EC}
.team-callout.marketing .team-tag{background:#8B4789;color:#fff}
.team-callout.brand{border-left-color:var(--pp-red-deep);background:#FFF0F0}
.team-callout.brand::before{content:"🍕";background:rgba(215,40,47,.15)}
.team-callout.brand .team-tag{background:var(--pp-red-deep);color:#fff}
.team-callout.newhire{border-left-color:#2F6690;background:#F0F6FB}
