  userAnswers = [];
  questionAnswered = false;
  const intro = document.getElementById('quiz-intro');
  if(intro) intro.style.display='none';
  document.getElementById('quiz-start').style.display='none';
  document.getElementById('quiz-results').style.display='none';
  document.getElementById('quiz-active').style.display='block';
  renderQuestion();
}

function renderQuestion(){
  const q = quizQuestions[currentQuestion];
  questionAnswered = false;
  document.getElementById('quiz-progress').textContent = `Question ${currentQuestion+1} of ${quizQuestions.length}`;
  document.getElementById('quiz-progress-fill').style.width = `${((currentQuestion)/quizQuestions.length)*100}%`;
  document.getElementById('quiz-question').innerHTML = q.q;
  const optionsHtml = q.options.map((opt,i)=>{
    const letter = String.fromCharCode(65+i);
    return `<button class="quiz-option" data-idx="${i}" onclick="selectAnswer(${i})"><span class="quiz-option-letter">${letter}</span><span>${opt}</span></button>`;
  }).join('');
  document.getElementById('quiz-options').innerHTML = optionsHtml;
  document.getElementById('quiz-feedback-wrap').innerHTML = '';
}

function selectAnswer(idx){
  if(questionAnswered) return;
  questionAnswered = true;
  const q = quizQuestions[currentQuestion];
  userAnswers.push(idx);
  const buttons = document.querySelectorAll('.quiz-option');
  buttons.forEach((btn,i)=>{
    btn.disabled = true;
    if(i === q.correct){ btn.classList.add(idx === q.correct ? 'correct' : 'show-correct'); }
    else if(i === idx){ btn.classList.add('incorrect'); }
  });
  const correct = idx === q.correct;
  const fb = document.createElement('div');
  fb.className = 'quiz-feedback ' + (correct ? 'right' : 'wrong');
  fb.innerHTML = correct
    ? '✅ Correct!'
    : `❌ Not quite. The correct answer is <strong>${String.fromCharCode(65+q.correct)}</strong>.`;
  const explainText = correct ? q.explain_right : q.explain_wrong;
  if(explainText){
    fb.innerHTML += `<div class="quiz-explain">${explainText}</div>`;
  }
  const isLast = currentQuestion === quizQuestions.length - 1;
  const btnLabel = isLast ? 'See Results →' : 'Next Question →';
  fb.innerHTML += `<br><button class="quiz-next-btn" onclick="nextQuestion()">${btnLabel}</button>`;
  document.getElementById('quiz-feedback-wrap').appendChild(fb);
}

function nextQuestion(){
  currentQuestion++;
  if(currentQuestion >= quizQuestions.length){ showResults(); }
  else { renderQuestion(); }
}

function showResults(){
  document.getElementById('quiz-active').style.display='none';
  let correctCount = 0;
  userAnswers.forEach((a,i)=>{ if(a === quizQuestions[i].correct) correctCount++; });
  const pct = Math.round((correctCount/quizQuestions.length)*100);
  const passed = correctCount >= PASS_THRESHOLD;
  const today = new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'});
  const resultsEl = document.getElementById('quiz-results');
  if(passed){
    resultsEl.innerHTML = `
      <div class="completion-wrap">
        <div class="completion-header">
          <span class="completion-emoji">🎉</span>
          <h3>Congratulations — You Passed!</h3>
          <div class="completion-sub">Pizza Pack Brand Knowledge Hub</div>
        </div>
        <div class="completion-card">
          <div class="completion-brand">
            <img src="https://pizzapack.com/cdn/shop/files/PP_Logo_Black.png" alt="Pizza Pack logo" class="logo-sm" onerror="this.style.display='none'">
            <div class="completion-brand-text">
              InvenTel Innovations
              <small>Product Knowledge Hub</small>
            </div>
          </div>
          <div class="completion-nameblock">
            <label for="trainee-name">Name · Title</label>
            <input id="trainee-name" type="text" placeholder="Jane Smith · CX Agent" oninput="syncName()" onkeydown="if(event.key==='Enter'){printCompletion();}">
            <div class="name-printed" id="name-printed">Name · Title</div>
          </div>
          <div class="completion-center-wrap"><div class="completion-badge">✓ Passed</div></div>
          <div class="completion-stats">
            <div class="completion-stat"><span class="completion-stat-label">Score</span><span class="completion-stat-value">${pct}%</span></div>
            <div class="completion-stat"><span class="completion-stat-label">Correct</span><span class="completion-stat-value">${correctCount}/${quizQuestions.length}</span></div>
            <div class="completion-stat"><span class="completion-stat-label">Date</span><span class="completion-stat-value" style="font-size:1rem">${today}</span></div>
            <div class="completion-stat"><span class="completion-stat-label">Result</span><span class="completion-stat-value" style="font-size:1rem">PASSED ✓</span></div>
          </div>
          <div class="completion-track">Training Track<strong>Pizza Pack — Brand Knowledge Hub</strong></div>
          <div class="completion-actions">
            <button class="btn-retake" onclick="startQuiz()">↩ Retake Quiz</button>
            <button class="btn-print" onclick="printCompletion()">🖨️ Print Certificate</button>
          </div>
        </div>
        <div style="max-width:520px;margin:18px auto 0;padding:14px 18px;background:rgba(255,255,255,.08);border:1px solid rgba(244,200,66,.25);border-radius:10px;color:var(--pp-cream);font-size:13px;line-height:1.6;text-align:center">
          <strong style="color:#fff">📨 Send to your HR onboarding trainer as proof of completion.</strong><br>
          Use <strong>🖨️ Print Certificate</strong> above — in the browser's print dialog, either send to a printer <em>or</em> choose <strong>&quot;Save as PDF&quot;</strong> as the destination. A clean screenshot of this completion card is also accepted.
        </div>
      </div>`;
  } else {
    resultsEl.innerHTML = `
      <div class="fail-header">
        <span class="fail-emoji">📚</span>
        <h3>Not quite — give it another shot</h3>
        <div class="fail-score">${correctCount} / ${quizQuestions.length} (${pct}%)</div>
        <p class="fail-msg">You'll need <strong>${PASS_THRESHOLD} correct (70%)</strong> to pass. Spend a few minutes reviewing the highest-value sections — Product Line, Wholesale, TV Specials, DRTV, Return Policy, Fulfillment, and Test Orders — then come back and crush it. You've got this.</p>
        <button class="quiz-retry-btn" onclick="startQuiz()">↩ Retake Quiz</button>
      </div>`;
  }
  resultsEl.style.display='block';
  document.getElementById('quiz-progress-fill').style.width = '100%';
}

function syncName(){
  const v = document.getElementById('trainee-name').value.trim();
  document.getElementById('name-printed').textContent = v || 'Name · Title';
}

function printCompletion(){
  const input = document.getElementById('trainee-name');
  if(!input.value.trim()){
    input.style.borderColor = 'var(--pp-danger)';
    input.placeholder = 'Please enter your name and title before printing';
    input.focus();
    setTimeout(()=>{ input.style.borderColor = ''; input.placeholder = 'Jane Smith · CX Agent'; }, 2500);
    return;
  }
  syncName();
  const quizSection = document.getElementById('quiz-section');
  quizSectionWasCollapsed = quizSection.classList.contains('collapsed');
  if(quizSectionWasCollapsed) quizSection.classList.remove('collapsed');
  document.body.classList.add('printing');
  setTimeout(()=>{
    window.print();
    setTimeout(()=>{
      document.body.classList.remove('printing');
      if(quizSectionWasCollapsed) quizSection.classList.add('collapsed');
    },100);
  },80);
}
window.addEventListener('afterprint',function(){
  document.body.classList.remove('printing');
  const quizSection = document.getElementById('quiz-section');
  if(quizSectionWasCollapsed) quizSection.classList.add('collapsed');
});

/* ============= HUB SEARCH ============= */
let searchIndex = [];
let activeResultIdx = -1;
let currentResults = [];

function buildSearchIndex(){
  searchIndex = [];
  // Sections (skip Hero + TOC)
  const sectionMeta = [
    {id:'overview',label:'Brand Overview',num:'01'},
    {id:'products',label:'Product Line',num:'02'},
    {id:'wholesale',label:'Wholesale & Custom Lids',num:'03'},
    {id:'tv-specials',label:'TV Specials',num:'04'},
    {id:'drtv',label:'DRTV Commercials',num:'05'},
    {id:'vision',label:'Vision, Mission & Pillars',num:'06'},
    {id:'voice',label:'Brand Voice & Tone',num:'07'},
    {id:'personality',label:'Brand Personality',num:'08'},
    {id:'visual',label:'Visual Identity',num:'09'},
    {id:'audience',label:'Audience & Personas',num:'10'},
    {id:'competitors',label:'Competitors & Positioning',num:'11'},
    {id:'objections',label:'Objection Handling',num:'12'},
    {id:'journey',label:'Customer Journey',num:'13'},
    {id:'data',label:'Survey & Use-Case Data',num:'14'},
    {id:'marketing',label:'Marketing Angles & Hooks',num:'15'},
    {id:'creatives',label:'Sample Winning Creatives',num:'16'},
    {id:'social',label:'Social & Digital',num:'17'},
    {id:'partners',label:'Partnerships & Influencer',num:'18'},
    {id:'discounts',label:'Discounts & Promo Codes',num:'19'},
    {id:'seo',label:'SEO',num:'20'},
    {id:'cro',label:'CRO',num:'21'},
    {id:'glossary',label:'Glossary',num:'22'},
    {id:'returns',label:'Return Policy',num:'23'},
    {id:'fulfillment',label:'Fulfillment & Shipping',num:'24'},
    {id:'test-orders',label:'Test Orders',num:'25'},
    {id:'shopify',label:'Shopify Platform',num:'26'},
    {id:'faq',label:'FAQ',num:'27'},
    {id:'resources',label:'Resources & Contacts',num:'28'},
    {id:'quiz-section',label:'Knowledge Check Quiz',num:'29'}
  ];
  sectionMeta.forEach(s=>{
    const el = document.getElementById(s.id);
    if(!el) return;
    let body = el.querySelector('.section-body') || el;
    const eyebrow = (body.querySelector('.eyebrow')?.innerText || '').trim();
    const subs = Array.from(body.querySelectorAll('h3,h4')).map(h=>h.innerText).join(' ');
    const paras = Array.from(body.querySelectorAll('p')).slice(0,3).map(p=>p.innerText).join(' ');
    const searchText = [s.label, eyebrow, subs, paras].join(' ').toLowerCase();
    searchIndex.push({type:'section',badgeClass:'section',id:s.id,title:`${s.num}. ${s.label}`,snippet:paras.slice(0,180),searchText});
  });
  // Team callouts
  document.querySelectorAll('.team-callout').forEach((el,i)=>{
    const teamClass = ['cx','creative','marketing','brand','newhire'].find(c=>el.classList.contains(c)) || 'cx';
    if(!el.id) el.id = 'cb-'+i;
    let title = (el.querySelector('.team-tag')?.innerText || '').trim();
    if(!title){
      const strong = el.querySelector('strong');
      if(strong){
        const t = strong.innerText.trim();
        if(t && !/^[$\d.\s]+$/.test(t)) title = t;
      }
    }
    if(!title){ const firstP = el.querySelector('p'); title = firstP ? firstP.innerText.split('.')[0].slice(0,60) : 'Callout'; }
    const bodyText = el.innerText;
    const teamLabels = {cx:'CX',creative:'Creative',marketing:'Marketing',brand:'Brand',newhire:'New Hire'};
    searchIndex.push({type:'callout',badgeClass:'callout-'+teamClass,badgeLabel:teamLabels[teamClass],id:el.id,title,snippet:bodyText.slice(0,180),searchText:(title+' '+bodyText).toLowerCase()});
  });
  // Glossary
  document.querySelectorAll('#glossary dt').forEach((dt,i)=>{
    if(!dt.id) dt.id = 'glo-'+i;
    const dd = dt.nextElementSibling;
    const term = dt.innerText.trim();
    const def = dd ? dd.innerText.trim() : '';
    searchIndex.push({type:'glossary',badgeClass:'glossary',badgeLabel:'Term',id:dt.id,title:term,snippet:def.slice(0,180),searchText:(term+' '+def).toLowerCase()});
  });
  // FAQ
  document.querySelectorAll('.faq-item').forEach((el,i)=>{
    if(!el.id) el.id = 'faq-'+i;
    const q = el.querySelector('.faq-q')?.innerText.trim() || '';
    const a = el.querySelector('.faq-a')?.innerText.trim() || '';
    searchIndex.push({type:'faq',badgeClass:'faq',badgeLabel:'FAQ',id:el.id,title:q,snippet:a.slice(0,180),searchText:(q+' '+a).toLowerCase()});
  });
  // Objections
  document.querySelectorAll('.objection').forEach((el,i)=>{
    if(!el.id) el.id = 'obj-'+i;
    const q = el.querySelector('.objection-q')?.innerText.trim() || '';
    const a = el.querySelector('.objection-a')?.innerText.trim() || '';
    searchIndex.push({type:'objection',badgeClass:'objection',badgeLabel:'Objection',id:el.id,title:q,snippet:a.slice(0,180),searchText:(q+' '+a).toLowerCase()});
  });
}

function escapeRegex(s){ return s.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'); }
function highlight(text, query){
  if(!query) return text;
  const tokens = query.split(/\s+/).filter(t=>t.length>=2).map(escapeRegex);
  if(!tokens.length) return text;
  const re = new RegExp('('+tokens.join('|')+')','gi');
  return text.replace(re,'<mark>$1</mark>');
}

function runSearch(query){
  const resultsEl = document.getElementById('nav-search-results');
  if(query.length < 2){
    resultsEl.classList.remove('open');
    resultsEl.innerHTML = '';
    return;
  }
  const q = query.toLowerCase().trim();
  const tokens = q.split(/\s+/).filter(Boolean);
  let matches = searchIndex.map(item=>{
    let score = 0;
    const t = item.title.toLowerCase();
    if(q.length <= 3){
      const wb = new RegExp('\\b'+escapeRegex(q)+'\\b','i');
      if(!wb.test(item.searchText)) return null;
      if(wb.test(t)) score += 50;
      score += 10;
    } else {
      if(t === q) score += 200;
      else if(t.startsWith(q)) score += 100;
      else if(t.includes(q)) score += 60;
      if(item.searchText.includes(q)) score += 20;
      else {
        // multi-token AND
        const allMatch = tokens.every(tok=>item.searchText.includes(tok));
        if(allMatch) score += 15;
        else return null;
      }
    }
    if(item.type === 'section') score += 5;
    return {item, score};
  }).filter(Boolean);
  matches.sort((a,b)=>b.score - a.score);
  matches = matches.slice(0,30);
  currentResults = matches.map(m=>m.item);
  activeResultIdx = -1;
  if(!matches.length){
    resultsEl.innerHTML = `<div class="search-empty"><strong>No matches for &quot;${query}&quot;</strong>Try a different term, a product name, a team, or a policy topic.</div>`;
    resultsEl.classList.add('open');
    return;
  }
  // Group
  const groupOrder = [
    {key:'section',label:'Sections',type:'section'},
    {key:'cx',label:'CX Callouts',type:'callout',cls:'callout-cx'},
    {key:'creative',label:'Creative Callouts',type:'callout',cls:'callout-creative'},
    {key:'marketing',label:'Marketing Callouts',type:'callout',cls:'callout-marketing'},
    {key:'brand',label:'Brand Callouts',type:'callout',cls:'callout-brand'},
    {key:'newhire',label:'New Hire Callouts',type:'callout',cls:'callout-newhire'},
    {key:'glossary',label:'Glossary',type:'glossary'},
    {key:'faq',label:'FAQ',type:'faq'},
    {key:'objection',label:'Objections',type:'objection'}
  ];
  let html = '';
  let resultIdx = 0;
  groupOrder.forEach(g=>{
    const inGroup = currentResults.filter(r=> g.type === 'callout' ? (r.type === 'callout' && r.badgeClass === g.cls) : r.type === g.key);
    if(!inGroup.length) return;
    html += `<div class="search-group"><div class="search-group-label">${g.label}<span class="search-group-count">${inGroup.length}</span></div>`;
    inGroup.forEach(r=>{
      const idx = resultIdx++;
      const titleHtml = highlight(r.title, q);
      const snippetHtml = highlight(r.snippet, q);
      const badgeText = r.type === 'section' ? 'Section' : (r.badgeLabel || 'Match');
      html += `<div class="search-result" data-idx="${idx}" data-target="${r.id}" onclick="jumpToResult(${idx})">
        <div class="search-result-top">
          <span class="search-result-badge ${r.badgeClass}">${badgeText}</span>
          <span class="search-result-title">${titleHtml}</span>
        </div>
        <div class="search-result-snippet">${snippetHtml}</div>
      </div>`;
    });
    html += '</div>';
  });
  resultsEl.innerHTML = html;
  resultsEl.classList.add('open');
  // Reorder currentResults to match render order
  const ordered = [];
  groupOrder.forEach(g=>{
    currentResults.forEach(r=>{
      if(g.type === 'callout' ? (r.type === 'callout' && r.badgeClass === g.cls) : r.type === g.key){ ordered.push(r); }
    });
  });
  currentResults = ordered;
}

function jumpToResult(idx){
  const r = currentResults[idx];
  if(!r) return;
  const target = document.getElementById(r.id);
  if(!target) return;
  // Auto-expand collapsed parents
  let el = target;
  while(el){
    if(el.classList && el.classList.contains('collapsed')){ el.classList.remove('collapsed'); }
    el = el.parentElement;
  }
  closeSearch();
  setTimeout(()=>{
    const navH = 76;
    const top = target.getBoundingClientRect().top + window.scrollY - navH;
    window.scrollTo({top, behavior:'smooth'});
    target.classList.remove('search-target-flash');
    void target.offsetWidth; // reflow
    target.classList.add('search-target-flash');
    setTimeout(()=>target.classList.remove('search-target-flash'), 2000);
  }, 150);
}

function closeSearch(){
  document.getElementById('nav-search-results').classList.remove('open');
}
function clearSearch(){
  const input = document.getElementById('nav-search-input');
  input.value = '';
  document.getElementById('nav-search-box').classList.remove('has-query');
  closeSearch();
  input.focus();
}

document.addEventListener('DOMContentLoaded',function(){
  buildSearchIndex();
  const input = document.getElementById('nav-search-input');
  const box = document.getElementById('nav-search-box');
  input.addEventListener('input',function(){
    box.classList.toggle('has-query', !!this.value);
    runSearch(this.value);
  });
  input.addEventListener('keydown',function(e){
    const results = document.querySelectorAll('.search-result');
    if(e.key === 'ArrowDown'){
      e.preventDefault();
      activeResultIdx = Math.min(activeResultIdx+1, results.length-1);
      updateActiveResult(results);
    } else if(e.key === 'ArrowUp'){
      e.preventDefault();
      activeResultIdx = Math.max(activeResultIdx-1, 0);
      updateActiveResult(results);
    } else if(e.key === 'Enter'){
      e.preventDefault();
      if(activeResultIdx >= 0){ jumpToResult(activeResultIdx); }
      else if(results.length === 1){ jumpToResult(0); }
      else if(results.length > 0){ jumpToResult(0); }
    } else if(e.key === 'Escape'){
      closeSearch();
    }
  });
  // Click outside closes
  document.addEventListener('click',function(e){
    if(!e.target.closest('.nav-search-wrap')){ closeSearch(); }
  });
  // / shortcut
  document.addEventListener('keydown',function(e){
    if(e.key === '/' && !['INPUT','TEXTAREA'].includes(document.activeElement.tagName)){
      e.preventDefault();
      input.focus();
    }
  });
});

function updateActiveResult(results){
  results.forEach((r,i)=>r.classList.toggle('active', i === activeResultIdx));
  if(activeResultIdx >= 0 && results[activeResultIdx]){
    results[activeResultIdx].scrollIntoView({block:'nearest'});
  }
}
</script>
